const rawInput = $input.first().json;
const input = (rawInput.body && typeof rawInput.body === 'object') ? rawInput.body : rawInput;
const searchParams = {
  q: `site:linkedin.com/in/ "${input.keyword}" "${input.city}"`,
  num: Math.min(input.limit || 10, 25)
};
return [{ json: { ...input, serper_search_params: searchParams } }];

const webhookRaw = $('On Webhook Trigger').first().json;
const webhook = (webhookRaw.body && typeof webhookRaw.body === 'object') ? webhookRaw.body : webhookRaw;

const results = $input.first().json.organic || [];
const linkedinId = 'cb000001-0000-0000-0000-000000000007';
const leadSourceId = webhook.lead_source_id || linkedinId;

const normalizeLinkedInUrl = (url) => {
  if (!url || typeof url !== 'string') return '';
  try {
    const u = new URL(url);
    u.search = '';
    u.hash = '';
    return u.toString().replace(/\/+$/, '');
  } catch {
    return url.trim().replace(/\/+$/, '');
  }
};

const leads = results.map(p => {
  const isCompany = p.link && p.link.includes('/company/');
  let firstName = 'Unknown';
  let lastName = '';
  let companyName = '';
  let jobTitle = '';

  if (isCompany) {
    companyName = (p.title || '').replace(' | LinkedIn', '').replace(' - LinkedIn', '').trim();
    firstName = 'Company';
  } else {
    const titleParts = (p.title || '').replace(' | LinkedIn', '').replace(' - LinkedIn', '').split(' - ');
    const name = titleParts[0] ? titleParts[0].trim() : 'Unknown';
    const nameParts = name.split(' ');
    firstName = nameParts[0] || 'Unknown';
    lastName = nameParts.slice(1).join(' ') || '';

    jobTitle = titleParts[1] ? titleParts[1].trim() : '';
    companyName = titleParts.length > 2
      ? titleParts.slice(2).join(' ').trim()
      : titleParts.length === 2 && !titleParts[1].includes(' at ') && !titleParts[1].toLowerCase().includes('freelance')
        ? titleParts[1].trim()
        : '';
  }

  const normalizedUrl = normalizeLinkedInUrl(p.link || '');
  const fallbackPlaceId = `linkedin:${[firstName, lastName, companyName, jobTitle, webhook.city || ''].join('|').toLowerCase().replace(/\s+/g, ' ').trim()}`;

  return {
    first_name: firstName,
    last_name: lastName,
    company_name: companyName,
    email: '',
    phone: '',
    job_title: jobTitle,
    city: webhook.city || '',
    province: '',
    lead_source_id: leadSourceId,
    estimated_value: 0,
    placeId: normalizedUrl || fallbackPlaceId,
    website: normalizedUrl || '',
    notes: [
      'Source: LinkedIn via Serper Google Search',
      `LinkedIn URL: ${p.link || 'N/A'}`,
      `Headline/Snippet: ${p.snippet || 'N/A'}`,
      `Keyword: ${webhook.keyword}`
    ].join('\n')
  };
});

return [{ json: { leads: leads, source: 'linkedin' } }];

// Map Serper Google Maps results directly to GIMS Lead interface
const webhookRaw = $('On Webhook Trigger').first().json;
const webhook = (webhookRaw.body && typeof webhookRaw.body === 'object') ? webhookRaw.body : webhookRaw;

const places = $input.first().json.places || [];
const mapsId = 'cb000001-0000-0000-0000-000000000006';
const leadSourceId = webhook.lead_source_id || mapsId;
const limit = Math.min(webhook.limit || 10, 20);

const normalizePlaceLink = (url) => {
  if (!url || typeof url !== 'string') return '';
  try {
    const u = new URL(url);
    u.search = '';
    u.hash = '';
    return u.toString().replace(/\/+$/, '');
  } catch {
    return url.trim().replace(/\/+$/, '');
  }
};

const toNumberInRange = (value, min, max) => {
  const n = Number(value);
  return Number.isFinite(n) && n >= min && n <= max ? n : null;
};

const extractFromGoogleMapsUrl = (url) => {
  if (!url || typeof url !== 'string') return { latitude: null, longitude: null };
  const match = url.match(/@(-?\d+(?:\.\d+)?),(-?\d+(?:\.\d+)?)/);
  if (!match) return { latitude: null, longitude: null };

  return {
    latitude: toNumberInRange(match[1], -90, 90),
    longitude: toNumberInRange(match[2], -180, 180),
  };
};

const extractCoordinates = (place) => {
  const candidates = [
    { latitude: place.latitude, longitude: place.longitude },
    { latitude: place.lat, longitude: place.lng },
    { latitude: place.lat, longitude: place.lon },
    { latitude: place.location?.lat, longitude: place.location?.lng },
    { latitude: place.location?.latitude, longitude: place.location?.longitude },
    { latitude: place.gpsCoordinates?.latitude, longitude: place.gpsCoordinates?.longitude },
    { latitude: place.coordinates?.lat, longitude: place.coordinates?.lng },
    { latitude: place.coordinates?.latitude, longitude: place.coordinates?.longitude },
  ];

  for (const candidate of candidates) {
    const latitude = toNumberInRange(candidate.latitude, -90, 90);
    const longitude = toNumberInRange(candidate.longitude, -180, 180);
    if (latitude !== null && longitude !== null) {
      return { latitude, longitude };
    }
  }

  return extractFromGoogleMapsUrl(place.link || '');
};

const leads = places.slice(0, limit).map(place => {
  const rawTitle = place.title || '';
  const nameParts = rawTitle.split(' ');
  const firstName = nameParts[0] || '';
  const lastName = nameParts.slice(1).join(' ') || '';

  const addressParts = (place.address || '').split(',').map(s => s.trim());
  let city = webhook.city || '';
  let province = '';

  if (addressParts.length > 0) {
    if (addressParts[addressParts.length - 1].toLowerCase() === 'indonesia') {
      if (addressParts.length >= 3) {
        city = addressParts[addressParts.length - 3].replace(/^(Kota|Kabupaten)\s+/i, '').trim();
        province = addressParts[addressParts.length - 2].replace(/\d+$/, '').trim();
      } else if (addressParts.length === 2) {
        province = addressParts[0].replace(/\d+$/, '').trim();
      }
    } else {
      if (addressParts.length >= 2) {
        city = addressParts[addressParts.length - 2].replace(/^(Kota|Kabupaten)\s+/i, '').trim();
        province = addressParts[addressParts.length - 1].replace(/\d+$/, '').trim();
      } else if (addressParts.length === 1) {
        province = addressParts[0].replace(/\d+$/, '').trim();
      }
    }
  }

  let email = '';
  if (place.website) {
    try {
      const domain = new URL(place.website).hostname.replace('www.', '');
      email = 'info@' + domain;
    } catch { }
  }

  const { latitude, longitude } = extractCoordinates(place);
  const mapQuery = latitude !== null && longitude !== null
    ? `https://maps.google.com/?q=${latitude},${longitude}`
    : (place.link || 'N/A');

  const fallbackPlaceID = `gmap:${[rawTitle, place.address || '', webhook.city || ''].join('|').toLowerCase().replace(/\s+/g, ' ').trim()}`;

  return {
    first_name: firstName,
    last_name: lastName,
    company_name: rawTitle,
    email: email,
    phone: place.phoneNumber || place.phone || '',
    job_title: place.type || (place.types && place.types[0]) || '',
    address: place.address || '',
    city: city,
    province: province,
    lead_source_id: leadSourceId,
    estimated_value: 0,
    latitude: latitude,
    longitude: longitude,
    rating: toNumberInRange(place.rating, 0, 5),
    ratingCount: Number.isFinite(Number(place.ratingCount)) ? Number(place.ratingCount) : null,
    types: Array.isArray(place.types) ? place.types.join(', ') : (place.type || ''),
    cid: place.cid || '',
    placeId: place.placeId || place.cid || normalizePlaceLink(place.link || '') || fallbackPlaceID,
    website: place.website || '',
    notes: [
      'Source: Google Maps',
      `Rating: ${place.rating || 'N/A'} (${place.ratingCount || 0} reviews)`,
      `Category: ${place.type || 'N/A'}`,
      `Coordinates: ${latitude ?? 'N/A'}, ${longitude ?? 'N/A'}`,
      `Map: ${mapQuery}`,
      `Website: ${place.website || 'N/A'}`,
      `CID: ${place.cid || 'N/A'}`,
      `Place ID: ${place.placeId || 'N/A'}`,
      `Keyword: ${webhook.keyword}`,
      `Scraped: ${new Date().toISOString()}`
    ].join('\n')
  };
});

return [{ json: { leads: leads, source: 'google_maps' } }];
